exercises.solution_code:
#include <iostream>

struct Counter {
    int value{0};

    Counter& increment() { ++value; return *this; }
    Counter& decrement() { --value; return *this; }
    Counter& add(int n)  { value += n; return *this; }
    Counter& reset()     { value = 0; return *this; }

    void print() const {
        std::cout << value << '\n';
    }
};

int main() {
    Counter c;
    c.increment().increment().increment().print(); // 3
    c.add(10).decrement().print();                 // 12
    c.reset().add(5).print();                      // 5
}

