exercises.solution_code:
#include <iostream>
#include <string>
#include <algorithm>

struct TextBuilder {
    std::string text{};
    int ops{0};

    TextBuilder& append(const std::string& s) {
        text += s;
        ++ops;
        return *this;
    }

    TextBuilder& prepend(const std::string& s) {
        text.insert(0, s);
        ++ops;
        return *this;
    }

    TextBuilder& toUpper() {
        std::transform(text.begin(), text.end(), text.begin(),
                       [](unsigned char c) { return static_cast<char>(std::toupper(c)); });
        ++ops;
        return *this;
    }

    void print() const {
        std::cout << text << '\n' << ops << '\n';
    }
};

int main() {
    std::string first, second, third;
    std::getline(std::cin, first);
    std::getline(std::cin, second);
    std::getline(std::cin, third);

    TextBuilder tb;
    tb.append(first).prepend(second).append(third).toUpper().print();
}

