exercises.solution_code:
#include <iostream>

class Rectangle {
public:
    Rectangle(int w, int h);
    int area() const { return m_width * m_height; }
    int perimeter() const;
    bool isSquare() const;
private:
    int m_width;
    int m_height;
};

inline Rectangle::Rectangle(int w, int h) : m_width{w}, m_height{h} {}

inline int Rectangle::perimeter() const { return 2 * (m_width + m_height); }

inline bool Rectangle::isSquare() const { return m_width == m_height; }

int main() {
    int w{}, h{};
    std::cin >> w >> h;
    Rectangle r{w, h};
    std::cout << "Area: " << r.area() << '\n';
    std::cout << "Perimeter: " << r.perimeter() << '\n';
    std::cout << "Is square: " << (r.isSquare() ? "yes" : "no") << '\n';
    return 0;
}

