exercises.solution_code:
#include <iostream>
#include <iomanip>

class TempLog {
public:
    TempLog& add(double t);
    int count() const;
    double minTemp() const;
    double maxTemp() const;
private:
    double m_readings[100]{};
    int m_count{0};
};

TempLog& TempLog::add(double t) {
    m_readings[m_count] = t;
    ++m_count;
    return *this;
}

int TempLog::count() const {
    return m_count;
}

double TempLog::minTemp() const {
    double min = m_readings[0];
    for (int i = 1; i < m_count; ++i) {
        if (m_readings[i] < min)
            min = m_readings[i];
    }
    return min;
}

double TempLog::maxTemp() const {
    double max = m_readings[0];
    for (int i = 1; i < m_count; ++i) {
        if (m_readings[i] > max)
            max = m_readings[i];
    }
    return max;
}

int main() {
    int n{};
    std::cin >> n;
    TempLog log;
    for (int i = 0; i < n; ++i) {
        double t{};
        std::cin >> t;
        log.add(t);
    }
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Count: " << log.count() << '\n';
    std::cout << "Min: " << log.minTemp() << '\n';
    std::cout << "Max: " << log.maxTemp() << '\n';
    return 0;
}

