exercises.solution_code:
#include <iostream>
#include <string>

class TrafficLight {
public:
    enum class Color { Red, Yellow, Green };

    void advance() {
        switch (m_color) {
            case Color::Red:    m_color = Color::Green;  break;
            case Color::Green:  m_color = Color::Yellow; break;
            case Color::Yellow: m_color = Color::Red;    break;
        }
    }

    Color current() const { return m_color; }

    std::string colorName() const {
        switch (m_color) {
            case Color::Red:    return "Red";
            case Color::Yellow: return "Yellow";
            case Color::Green:  return "Green";
        }
        return "";
    }

private:
    Color m_color { Color::Red };
};

int main() {
    int n{};
    std::cin >> n;

    TrafficLight light{};
    for (int i = 0; i < n; ++i)
        light.advance();

    std::cout << light.colorName() << '\n';
    return 0;
}

