exercises.solution_code:
#include <iostream>
#include <string>

class Card {
public:
    enum class Suit { Clubs, Diamonds, Hearts, Spades };

    Card& setSuit(Suit s) { m_suit = s; return *this; }
    Card& setRank(int r)  { m_rank = r; return *this; }

    std::string suitName() const {
        switch (m_suit) {
            case Suit::Clubs:    return "Clubs";
            case Suit::Diamonds: return "Diamonds";
            case Suit::Hearts:   return "Hearts";
            case Suit::Spades:   return "Spades";
        }
        return "";
    }

    std::string rankName() const {
        if (m_rank == 1)  return "Ace";
        if (m_rank == 11) return "Jack";
        if (m_rank == 12) return "Queen";
        if (m_rank == 13) return "King";
        return std::to_string(m_rank);
    }

    void print() const {
        std::cout << rankName() << " of " << suitName() << '\n';
    }

private:
    Suit m_suit { Suit::Clubs };
    int  m_rank { 1 };
};

int main() {
    int suitIndex{}, rank{};
    std::cin >> suitIndex >> rank;

    Card card{};
    card.setSuit(static_cast<Card::Suit>(suitIndex)).setRank(rank).print();
    return 0;
}

