#include <iostream>
#include <cstddef>
#include <sstream>
#include <string>

template <typename T, std::size_t N = 16>
class Stack {
    T data[N]{};
    std::size_t count{0};
public:
    void push(const T& value) {
        if (count < N) data[count++] = value;
    }
    void pop() {
        if (count > 0) --count;
    }
    T top() const { return data[count - 1]; }
    bool empty() const { return count == 0; }
    std::size_t size() const { return count; }
};

int main() {
    Stack<int> s{};

    std::string line;
    std::getline(std::cin, line);
    std::istringstream iss{line};
    int val{};
    while (iss >> val && val != 0)
        s.push(val);

    while (!s.empty()) {
        std::cout << s.top() << '\n';
        s.pop();
    }
    return 0;
}

