#include <iostream>

class Distance {
    int m_meters{};
    int m_centimeters{};

public:
    Distance(int meters, int centimeters)
        : m_meters{meters}, m_centimeters{centimeters} {}

    friend std::ostream& operator<<(std::ostream& os, const Distance& d);
    friend Distance addDistance(const Distance& a, const Distance& b);
};

std::ostream& operator<<(std::ostream& os, const Distance& d) {
    return os << d.m_meters << " m " << d.m_centimeters << " cm";
}

Distance addDistance(const Distance& a, const Distance& b) {
    int totalCm = a.m_centimeters + b.m_centimeters;
    int totalM  = a.m_meters + b.m_meters + totalCm / 100;
    totalCm %= 100;
    return Distance{totalM, totalCm};
}

int main() {
    int m1, c1, m2, c2;
    std::cin >> m1 >> c1 >> m2 >> c2;

    Distance d1{m1, c1};
    Distance d2{m2, c2};
    Distance sum = addDistance(d1, d2);

    std::cout << "d1: "  << d1  << "\n";
    std::cout << "d2: "  << d2  << "\n";
    std::cout << "sum: " << sum << "\n";

    return 0;
}

