#include <iostream>

class Temperature {
    double value{};
    char unit{};
public:
    Temperature(double v, char u) : value{v}, unit{u} {}

    static double toCelsius(double val, char u) {
        if (u == 'F')
            return (val - 32.0) * 5.0 / 9.0;
        return val;
    }

    friend std::ostream& operator<<(std::ostream& out, const Temperature& t);
    friend const Temperature* hotter(const Temperature& a, const Temperature& b);
};

std::ostream& operator<<(std::ostream& out, const Temperature& t) {
    out << t.value << " degrees " << t.unit;
    return out;
}

const Temperature* hotter(const Temperature& a, const Temperature& b) {
    double ca = Temperature::toCelsius(a.value, a.unit);
    double cb = Temperature::toCelsius(b.value, b.unit);
    if (ca > cb) return &a;
    if (cb > ca) return &b;
    return nullptr;
}

int main() {
    double v1, v2;
    char u1, u2;
    std::cin >> v1 >> u1 >> v2 >> u2;

    Temperature t1{v1, u1};
    Temperature t2{v2, u2};

    std::cout << t1 << '\n';
    std::cout << t2 << '\n';

    const Temperature* h = hotter(t1, t2);
    if (h == nullptr)
        std::cout << "Equal\n";
    else
        std::cout << "Hotter: " << *h << '\n';

    return 0;
}

