#include <iostream>
#include <string>
#include <string_view>
#include <utility>

class QueryBuilder {
public:
    QueryBuilder& append(std::string_view part) {
        buf += part;
        buf += ' ';
        return *this;
    }

    std::string build() const & {
        std::string result = buf;
        if (!result.empty() && result.back() == ' ')
            result.pop_back();
        return result;
    }

    std::string build() && {
        if (!buf.empty() && buf.back() == ' ')
            buf.pop_back();
        return std::move(buf);
    }

private:
    std::string buf;
};

int main() {
    QueryBuilder qb;
    std::string line;
    while (std::getline(std::cin, line)) {
        qb.append(line);
    }
    std::cout << qb.build() << '\n';
